ON CONFLICT (from_ticker,to_ticker) DO UPDATE SET seo_title=EXCLUDED.seo_title, seo_description=EXCLUDED.seo_description, seo_h1=EXCLUDED.seo_h1, is_valid=true, last_synced_at=now();

UPDATE public.sync_engine_state SET pairs_count = (SELECT count(*) FROM public.pairs WHERE is_valid=true), updated_at=now() WHERE id = 1;